activity_state_enum.codigo:
enum ActivityState {
  trabajando,
  inactivo,
  distraido,
  fatiga,
  ausente;

  String get label {
    switch (this) {
      case ActivityState.trabajando: return 'TRABAJANDO';
      case ActivityState.inactivo: return 'INACTIVO';
      case ActivityState.distraido: return 'DISTRAÍDO';
      case ActivityState.fatiga: return 'FATIGA';
      case ActivityState.ausente: return 'AUSENTE';
    }
  }

  String get emoji {
    switch (this) {
      case ActivityState.trabajando: return '🟢';
      case ActivityState.inactivo: return '🟡';
      case ActivityState.distraido: return '🟠';
      case ActivityState.fatiga: return '🔴';
      case ActivityState.ausente: return '⚫';
    }
  }
}

